@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (_initError is not null)
{
    <div class="@($"flex items-center justify-center text-sm text-destructive border border-destructive/30 rounded-md bg-destructive/5 {Class}".Trim())" @attributes="AdditionalAttributes">
        <span>@_initError</span>
    </div>
}
else
{
    <div class="@($"flex flex-col gap-3 rounded-md border border-border/60 bg-card p-3 min-w-0 w-full {Class}".Trim())" @attributes="AdditionalAttributes" style="min-width: 0; width: 100%;">
        @* Lumeo-styled toolbar above the Frappe Gantt canvas. We suppress
           Quarter Day / Half Day from the control bar to keep the common case
           simple — power users can still pass them through the `ViewMode` param. *@
        <div class="flex flex-wrap items-center justify-between gap-2">
            <ToggleGroup Type="ToggleGroup.ToggleGroupType.Single"
                         Variant="ToggleGroup.ToggleGroupVariant.Outline"
                         Size="Lumeo.Size.Sm"
                         Value="@_toolbarViewValue"
                         ValueChanged="OnViewModeChangedAsync">
                @foreach (var level in ResolvedZoomLevels)
                {
                    <ToggleGroupItem Value="@level.ToString()">@L[ZoomLabelKey(level)]</ToggleGroupItem>
                }
            </ToggleGroup>
            @if (TrailingContent is not null)
            {
                <div class="flex items-center gap-2">
                    @TrailingContent
                </div>
            }
        </div>

        @* Grid wrapper with minmax(0, 1fr) — well-known trick to defeat the
           min-content cascade without touching containment. The 1fr column
           has min size 0, so the SVG inside cannot push the wrapper wider
           than its parent.
           Height: use max-height (cap) instead of fixed height so the chart
           shrinks to fit its content (header + N tasks * row height) and
           only scrolls vertically when the task list exceeds @Height. *@
        <div style="display: grid; grid-template-columns: minmax(0, 1fr); width: 100%;">
            <div @ref="_hostRef" class="lumeo-gantt-host" style="overflow-x: auto; overflow-y: auto; max-height: @Height; min-width: 0;"></div>
        </div>
    </div>
}

@code {
    [Parameter] public IEnumerable<GanttTask>? Tasks { get; set; }
    [Parameter] public EventCallback<IEnumerable<GanttTask>> TasksChanged { get; set; }
    [Parameter] public GanttViewMode ViewMode { get; set; } = GanttViewMode.Day;
    /// <summary>
    /// Raised when the user picks a new zoom level from the toolbar. Bind it
    /// (<c>@bind-ViewMode</c>) to keep the parent's <see cref="ViewMode"/> in
    /// lock-step with the toolbar; without a binding the component still tracks
    /// the toolbar selection on its own (uncontrolled usage).
    /// </summary>
    [Parameter] public EventCallback<GanttViewMode> ViewModeChanged { get; set; }
    /// <summary>
    /// Restricts which zoom buttons the toolbar renders, in the given order. When null
    /// or empty the full default set (<c>Day, Week, Month, Year</c>) is shown — matching
    /// the previous hardcoded toolbar. Only toolbar-representable levels are drawn:
    /// <see cref="GanttViewMode.QuarterDay"/> / <see cref="GanttViewMode.HalfDay"/> have
    /// no toolbar button and are silently skipped here (still settable via
    /// <see cref="ViewMode"/>). Example: <c>ZoomLevels="new[]{ GanttViewMode.Day,
    /// GanttViewMode.Week, GanttViewMode.Month }"</c>.
    /// </summary>
    [Parameter] public IReadOnlyList<GanttViewMode>? ZoomLevels { get; set; }
    /// <summary>
    /// The zoom level selected on first render. When set it seeds the initial toolbar
    /// selection (and the level the timeline mounts at), overriding <see cref="ViewMode"/>'s
    /// default — handy for uncontrolled usage, e.g. <c>ZoomLevels="…" DefaultZoom="GanttViewMode.Week"</c>.
    /// After mount, <see cref="ViewMode"/> / <c>@bind-ViewMode</c> govern as before. Null
    /// falls back to <see cref="ViewMode"/> (the existing behaviour).
    /// </summary>
    [Parameter] public GanttViewMode? DefaultZoom { get; set; }
    [Parameter] public EventCallback<GanttTask> OnTaskClick { get; set; }
    [Parameter] public EventCallback<GanttTask> OnDateChange { get; set; }
    [Parameter] public EventCallback<GanttTask> OnProgressChange { get; set; }
    [Parameter] public string Height { get; set; } = "500px";
    [Parameter] public bool Readonly { get; set; }
    /// <summary>Highlight today with a vertical line and dot marker. Default true.</summary>
    [Parameter] public bool TodayHighlight { get; set; } = true;
    /// <summary>Override the pixel height of each task bar (default 22).</summary>
    [Parameter] public int? BarHeight { get; set; }
    /// <summary>Override the pixel width of each date column for the current view mode.</summary>
    [Parameter] public int? ColumnWidth { get; set; }
    /// <summary>
    /// Per-task bar colour override. Return a CSS colour string (hex, rgb, or a
    /// CSS variable reference like "var(--color-destructive)") or null to use the
    /// primary theme colour.
    /// </summary>
    [Parameter] public Func<GanttTask, string?>? BarColor { get; set; }
    /// <summary>
    /// Optional grouping function. When set, tasks are sorted by group label and
    /// a visual section-header row is injected before the first task in each group.
    /// </summary>
    [Parameter] public Func<GanttTask, string>? GroupBy { get; set; }
    [Parameter] public RenderFragment? TrailingContent { get; set; }
    [Parameter] public EventCallback<string> OnInitError { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private ElementReference _hostRef;
    private string? _initError;
    private DotNetObjectReference<Gantt>? _selfRef;
    private string? _instanceId;
    private bool _initialized;
    // Guards against a second GanttInitAsync being launched while the first is
    // still in flight. Because init is no longer latched to firstRender (it can be
    // re-attempted after a recoverable failure), an extra render that lands during
    // the async init handshake would otherwise re-enter and fire a duplicate
    // gantt.init. Set true before the await, cleared in finally.
    private bool _initializing;
    private int _lastTasksHash;
    // Hash of the task payload the PARENT last supplied through the `Tasks`
    // parameter (folding in the BarColor / GroupBy delegate output, which are
    // also parent-owned). Unlike _lastTasksHash, this is advanced ONLY by a
    // genuine parameter change — never by a local JS drag/progress edit via
    // ReplaceTask. In UNCONTROLLED usage (no TasksChanged binding) OnParametersSetAsync
    // re-pushes to JS only when THIS moves, so a stale parent re-render after an
    // uncontrolled drag no longer snaps the bars back to their pre-drag positions
    // (battle-test wave 1, finding #18).
    private int _lastParentHash;
    // CONTROLLED discriminator: the hash of the local _tasks snapshot we last pushed UP
    // via TasksChanged (also re-synced whenever we adopt an authoritative Tasks payload).
    // A controlled parent re-render that echoes back this exact hash is safe to ignore
    // (keep the in-flight drag/progress edit); any other hash — including one equal to
    // the PRE-drag parent hash — is an authoritative assertion (veto / normalization /
    // reset) and must win, rolling the local _tasks back to it.
    private int _lastPushedTasksHash;
    private GanttViewMode _currentViewMode;
    // Last value seen on the ViewMode parameter. Used for UNCONTROLLED usage: we only
    // treat ViewMode as authoritative when this changes — otherwise a parent re-render
    // with an unchanged ViewMode would clobber a toolbar selection the user just made.
    private GanttViewMode _lastSeenViewMode;
    // CONTROLLED discriminator: the last value we pushed UP via ViewModeChanged (also
    // re-synced whenever we adopt an authoritative ViewMode). A controlled parent
    // re-render that echoes back this exact value is safe to ignore (keep the toolbar
    // selection); any other value is an authoritative assertion (veto / reset) and must win.
    private GanttViewMode _lastPushedViewMode;

    // Snapshot of the current tasks used when the JS layer reports a drag
    // or progress change — avoids reaching back into `Tasks` (which may have
    // been replaced by the parent between render cycles).
    private List<GanttTask> _tasks = new();

    // The toolbar only exposes Day/Week/Month/Year. When the caller passes a
    // QuarterDay / HalfDay view mode (or a ZoomLevels subset that excludes the
    // current level), we keep the toggle group unselected.
    private string? _toolbarViewValue => _currentViewMode switch
    {
        GanttViewMode.Day => "Day",
        GanttViewMode.Week => "Week",
        GanttViewMode.Month => "Month",
        GanttViewMode.Year => "Year",
        _ => null,
    };

    // The toolbar-representable levels, in canonical order. QuarterDay / HalfDay are
    // deliberately excluded — they have no localized toolbar label and were never
    // rendered as buttons (they remain settable through the ViewMode parameter).
    private static readonly GanttViewMode[] _defaultZoomLevels =
    {
        GanttViewMode.Day, GanttViewMode.Week, GanttViewMode.Month, GanttViewMode.Year,
    };

    // Levels to render as toolbar buttons: the caller's ZoomLevels subset (order
    // preserved, non-toolbar levels filtered out), else the full default set.
    private IReadOnlyList<GanttViewMode> ResolvedZoomLevels =>
        ZoomLevels is { Count: > 0 }
            ? ZoomLevels.Where(l => Array.IndexOf(_defaultZoomLevels, l) >= 0).ToList()
            : _defaultZoomLevels;

    private static string ZoomLabelKey(GanttViewMode level) => level switch
    {
        GanttViewMode.Day => "Gantt.Day",
        GanttViewMode.Week => "Gantt.Week",
        GanttViewMode.Month => "Gantt.Month",
        GanttViewMode.Year => "Gantt.Year",
        _ => "Gantt.Day",
    };

    protected override void OnInitialized()
    {
        // DefaultZoom (when set) seeds the initial toolbar selection + the level the
        // timeline mounts at, overriding ViewMode's default. The *-SeenViewMode /
        // -PushedViewMode discriminators still track the ViewMode PARAMETER so the
        // controlled/uncontrolled change-detection in OnParametersSetAsync is unchanged.
        _currentViewMode = DefaultZoom ?? ViewMode;
        _lastSeenViewMode = ViewMode;
        _lastPushedViewMode = ViewMode;
        _tasks = SortedTasks(Tasks?.ToList() ?? new List<GanttTask>());
        _lastTasksHash = ComputeTasksHash(_tasks);
        _lastParentHash = _lastTasksHash;
        _lastPushedTasksHash = _lastTasksHash;
        _lastOptionsHash = ComputeOptionsHash();
    }

    // The init-only render options (Readonly / TodayHighlight / BarHeight /
    // ColumnWidth) used to be captured ONCE in the GanttInitAsync options bag, so
    // changing any of them after init was silently dropped (battle-test wave 1 #2).
    // We now fingerprint them and push the new bag to the live instance via
    // gantt.refresh whenever the fingerprint changes.
    private int _lastOptionsHash;
    private int ComputeOptionsHash() => System.HashCode.Combine(Readonly, TodayHighlight, BarHeight, ColumnWidth);

    // When GroupBy is set, sort tasks so that each group clusters together.
    // The original relative order within a group is preserved (stable sort).
    private List<GanttTask> SortedTasks(List<GanttTask> raw)
    {
        if (GroupBy is null) return raw;
        return raw
            .Select((t, i) => (t, i))
            .OrderBy(x => GroupBy(x.t))
            .ThenBy(x => x.i)
            .Select(x => x.t)
            .ToList();
    }

    protected override async Task OnParametersSetAsync()
    {
        // CONTROLLED (ViewModeChanged bound): adopt the incoming ViewMode whenever it
        // differs from what we last pushed via ViewModeChanged. An echo of our own push
        // is a no-op (keep the toolbar selection); anything else — including a veto that
        // lands back on the pre-click parent value — is authoritative and must win, so
        // the toolbar rolls back to it.
        // UNCONTROLLED: only a genuine change against the last value we SAW as a
        // parameter is authoritative — comparing against _lastSeenViewMode (not
        // _currentViewMode) means an unchanged ViewMode on a parent re-render leaves a
        // toolbar selection intact, so the user's zoom no longer silently reverts.
        var viewModeChanged = ViewModeChanged.HasDelegate
            ? ViewMode != _lastPushedViewMode
            : ViewMode != _lastSeenViewMode;
        if (viewModeChanged)
        {
            _currentViewMode = ViewMode;
            _lastPushedViewMode = ViewMode;
            if (_initialized && _instanceId is not null)
                await Interop.GanttChangeViewModeAsync(_instanceId, ViewMode.ToString());
        }
        _lastSeenViewMode = ViewMode;

        // If a previous GanttInitAsync threw, the component latched into the
        // error state (_initError set, _initialized false, _instanceId null) and
        // OnAfterRenderAsync stopped retrying. A later parameter change is the
        // signal that the world may have moved on (the host element re-appeared,
        // the JS module was reloaded, the caller supplied new Tasks/ViewMode), so
        // clear the error to let OnAfterRenderAsync re-attempt init on the next
        // render instead of staying permanently dead (battle-test wave 1, #19).
        if (_initError is not null && !_initialized
            && (viewModeChanged || Tasks is not null))
        {
            // Re-seed the snapshot from the latest Tasks so the retried init
            // mounts the current data, not the stale list captured at first init.
            _tasks = SortedTasks(Tasks?.ToList() ?? new List<GanttTask>());
            _lastTasksHash = ComputeTasksHash(_tasks);
            _lastParentHash = _lastTasksHash;
            _lastPushedTasksHash = _lastTasksHash;
            // Clearing the error makes the razor render the host element again on
            // the render that follows OnParametersSetAsync; OnAfterRenderAsync then
            // sees no instance + no error and re-attempts init against that host.
            _initError = null;
        }

        if (!_initialized || _instanceId is null) return;

        // Push changed init-only render options (Readonly/TodayHighlight/BarHeight/
        // ColumnWidth) to the live instance — these are NOT folded into the tasks
        // payload, so without this they only ever applied at init (#2).
        var optionsHash = ComputeOptionsHash();
        if (optionsHash != _lastOptionsHash)
        {
            _lastOptionsHash = optionsHash;
            await Interop.GanttRefreshAsync(_instanceId, new
            {
                @readonly = Readonly,
                todayHighlight = TodayHighlight,
                barHeight = BarHeight,
                columnWidth = ColumnWidth,
            });
        }

        if (Tasks is not null)
        {
            var incoming = SortedTasks(Tasks.ToList());
            var hash = ComputeTasksHash(incoming);
            // CONTROLLED (TasksChanged bound): gate the re-push on the PUSHED hash, not
            // the parent hash. A controlled parent re-render that echoes back exactly
            // the hash we last pushed via TasksChanged is a no-op (keep the in-flight
            // drag/progress edit); anything else — including a veto that lands back on
            // the PRE-drag parent hash — is authoritative and must win, rolling the
            // bars back to it.
            // UNCONTROLLED: gate on the PARENT hash, not _lastTasksHash. A local JS
            // drag/progress edit advances _lastTasksHash (via ReplaceTask) but NOT
            // _lastParentHash, so an uncontrolled parent re-render that still
            // carries the original (pre-drag) Tasks is seen as "parent unchanged"
            // and the bars are left where the user dropped them. Only a genuinely
            // new parent payload (different records, or a swapped BarColor/GroupBy
            // delegate output) moves _lastParentHash and re-pushes to JS.
            var parentMoved = TasksChanged.HasDelegate
                ? hash != _lastPushedTasksHash
                : hash != _lastParentHash;
            if (parentMoved)
            {
                _lastTasksHash = hash;
                _lastPushedTasksHash = hash;
                _tasks = incoming;
                await Interop.GanttSetTasksAsync(_instanceId, incoming.Select(ToJsTask).Cast<object>());
            }
            _lastParentHash = hash;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Init is no longer latched to firstRender. We attempt it whenever the
        // component has no live instance yet AND is not currently parked in the
        // error state. A failed init sets _initError, which blocks further auto-
        // retries here until OnParametersSetAsync clears it on the next relevant
        // parameter change — so a transient init failure is recoverable rather
        // than permanently dead (battle-test wave 1, #19).
        if (_initialized || _instanceId is not null || _initError is not null || _initializing) return;

        // Reuse the DotNetObjectReference across retries so a second attempt does
        // not leak the first one.
        _selfRef ??= DotNetObjectReference.Create(this);

        var options = new
        {
            tasks = _tasks.Select(ToJsTask).ToArray(),
            // Mount at the effective current level so DefaultZoom is honoured on first paint.
            viewMode = _currentViewMode.ToString(),
            @readonly = Readonly,
            todayHighlight = TodayHighlight,
            barHeight = BarHeight,
            columnWidth = ColumnWidth,
        };

        _initializing = true;
        try
        {
            _instanceId = await Interop.GanttInitAsync(_hostRef, _selfRef, options);
            _initialized = true;
        }
        catch (Microsoft.JSInterop.JSDisconnectedException)
        {
            // Circuit was torn down between firstRender starting and
            // GanttInitAsync resolving. No init-error UI to show because the
            // user is already gone — match the pattern other components use.
        }
        catch (Microsoft.JSInterop.JSException ex)
        {
            _initError = $"Gantt initialization failed: {ex.Message}";
            Console.Error.WriteLine($"[Lumeo Gantt] Init failed: {ex.Message}");
            if (OnInitError.HasDelegate)
                await OnInitError.InvokeAsync(ex.Message);
            StateHasChanged();
        }
        finally
        {
            _initializing = false;
        }
    }

    private object ToJsTask(GanttTask t)
    {
        // For milestones render as zero-duration (start == end) so the renderer
        // picks them up and draws a diamond shape.
        var end = t.IsMilestone ? t.Start : t.End;
        return new
        {
            id = t.Id,
            name = t.Name,
            start = t.Start.ToString("yyyy-MM-dd"),
            end = end.ToString("yyyy-MM-dd"),
            progress = t.Progress,
            dependencies = t.Dependencies ?? Array.Empty<string>(),
            custom_class = t.CustomClass,
            is_milestone = t.IsMilestone,
            group_label = t.GroupLabel,
            bar_color = BarColor?.Invoke(t),
        };
    }

    // Instance (not static) because the change-detection has to fold in the
    // per-task OUTPUT of the BarColor and GroupBy delegates. Those delegates are
    // the only task properties whose rendered result lives outside the GanttTask
    // record itself: a parent can swap the BarColor lambda (recolour every bar)
    // or the GroupBy lambda (re-cluster the lanes) while leaving the task list
    // value-identical. Both feed the per-task JS payload (bar_color / group_label
    // + the SortedTasks order), so re-pushing tasks via GanttSetTasksAsync applies
    // them — but only if the hash actually moves when the delegate output does.
    private int ComputeTasksHash(IEnumerable<GanttTask> tasks)
    {
        // Cheap identity hash — good enough to detect "did the caller swap the
        // tasks list (or recolour/regroup it)?" without a JS round-trip on every
        // render.
        var hash = new HashCode();
        foreach (var t in tasks)
        {
            hash.Add(t.Id);
            hash.Add(t.Name);
            hash.Add(t.Start);
            hash.Add(t.End);
            hash.Add(t.Progress);
            hash.Add(t.CustomClass);
            hash.Add(t.IsMilestone);
            hash.Add(t.GroupLabel);
            if (t.Dependencies is not null)
                foreach (var d in t.Dependencies) hash.Add(d);
            // Fold the delegate output so a BarColor / GroupBy swap that leaves the
            // GanttTask records untouched is still detected and re-pushed.
            hash.Add(BarColor?.Invoke(t));
            hash.Add(GroupBy?.Invoke(t));
        }
        return hash.ToHashCode();
    }

    private async Task OnViewModeChangedAsync(string? v)
    {
        if (string.IsNullOrEmpty(v)) return;
        if (!Enum.TryParse<GanttViewMode>(v, out var parsed)) return;
        if (parsed == _currentViewMode) return;

        _currentViewMode = parsed;
        // Deliberately do NOT touch _lastSeenViewMode here: it tracks the value
        // the *parent* last passed via ViewMode. Leaving it untouched means a
        // subsequent parent re-render that still carries the original (constant)
        // ViewMode is seen as "unchanged" and no longer clobbers this toolbar
        // selection — which is exactly the revert bug. Uncontrolled usage relies on
        // this; controlled (@bind-ViewMode) usage instead re-syncs through
        // OnParametersSetAsync via _lastPushedViewMode below.

        // Record _lastPushedViewMode BEFORE invoking ViewModeChanged: a controlled
        // parent re-renders synchronously inside InvokeAsync, so OnParametersSetAsync
        // must already see this value as "the value we just pushed" to distinguish an
        // accepted echo (keep the toolbar selection) from a veto (parent kept its old
        // value -> roll back).
        _lastPushedViewMode = parsed;

        // Keep a bound parent's ViewMode in lock-step with the toolbar. Without
        // a binding this is a no-op and the component stays uncontrolled.
        if (ViewModeChanged.HasDelegate)
            await ViewModeChanged.InvokeAsync(parsed);

        // The renderer is only present once JS init has handed back an id.
        if (_instanceId is not null)
            await Interop.GanttChangeViewModeAsync(_instanceId, parsed.ToString());
    }

    [JSInvokable]
    public async Task JsOnTaskClick(GanttTask t)
    {
        if (OnTaskClick.HasDelegate) await OnTaskClick.InvokeAsync(t);
    }

    [JSInvokable]
    public async Task JsOnDateChange(GanttTask t)
    {
        ReplaceTask(t);
        if (OnDateChange.HasDelegate) await OnDateChange.InvokeAsync(t);
        if (TasksChanged.HasDelegate)
        {
            // Record _lastPushedTasksHash BEFORE invoking TasksChanged: a controlled
            // parent re-renders synchronously inside InvokeAsync, so OnParametersSetAsync
            // must already see this hash as "the value we just pushed" to distinguish an
            // accepted echo (keep the in-flight edit) from a veto (parent kept its old
            // value -> roll back).
            _lastPushedTasksHash = _lastTasksHash;
            await TasksChanged.InvokeAsync(_tasks.ToList());
        }
    }

    [JSInvokable]
    public async Task JsOnProgressChange(GanttTask t)
    {
        ReplaceTask(t);
        if (OnProgressChange.HasDelegate) await OnProgressChange.InvokeAsync(t);
        if (TasksChanged.HasDelegate)
        {
            // See JsOnDateChange — record the pushed-hash discriminator before invoking.
            _lastPushedTasksHash = _lastTasksHash;
            await TasksChanged.InvokeAsync(_tasks.ToList());
        }
    }

    private void ReplaceTask(GanttTask t)
    {
        var idx = _tasks.FindIndex(x => x.Id == t.Id);
        if (idx >= 0) _tasks[idx] = t;
        _lastTasksHash = ComputeTasksHash(_tasks);
    }

    public async ValueTask DisposeAsync()
    {
        if (_instanceId is not null)
        {
            try { await Interop.GanttDestroyAsync(_instanceId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        _selfRef?.Dispose();
    }
}

namespace Lumeo;

/// <summary>
/// A task bar rendered on the Gantt chart. Used as the data contract between
/// Blazor and the Lumeo SVG Gantt renderer.
/// </summary>
public record GanttTask(
    string Id,
    string Name,
    DateTime Start,
    DateTime End,
    int Progress = 0,                // 0-100
    string[]? Dependencies = null,   // array of Task Ids
    string? CustomClass = null,
    bool IsMilestone = false,        // renders as a diamond; zero-duration point event
    string? GroupLabel = null        // optional swim-lane / group header label
);

/// <summary>
/// Gantt timeline zoom level. Supported by the Lumeo SVG engine:
/// QuarterDay = 6-hour columns, HalfDay = 12-hour columns,
/// Day = 1 column/day, Week = 1 column/week,
/// Month = 1 column/month, Year = 1 column/year.
/// </summary>
public enum GanttViewMode
{
    QuarterDay,
    HalfDay,
    Day,
    Week,
    Month,
    Year
}
